import hashlib

def calculate_file_hash(filepath, method='sha256'):
    if not hasattr(hashlib, method):
        raise ValueError('Unsupported hash method')
        
    h = getattr(hashlib, method)()
    
    with open(filepath, 'rb') as file:
        chunk = 0
        while chunk != b'':
            chunk = file.read(1024)
            h.update(chunk)
            
    return h.hexdigest()